<?php if(!defined('ABSPATH')){exit;}class AuthMe_DB_Schema{public static function otp_table(){global $wpdb;return $wpdb->prefix.'authme_otp_storage';}public static function host_request_table(){global $wpdb;return $wpdb->prefix.'host_request';}public static function otp_table_schema(){return array('id'=>array('type'=>'INT(11)','null'=>false,'default'=>null,'extra'=>'AUTO_INCREMENT','key'=>'PRIMARY','comment'=>'Unique auto-increment row identifier.',),'email'=>array('type'=>'VARCHAR(100)','null'=>false,'default'=>null,'extra'=>null,'key'=>'INDEX (composite: email_purpose)','comment'=>'Email address the OTP was sent to.',),'otp_code'=>array('type'=>'VARCHAR(6)','null'=>false,'default'=>null,'extra'=>null,'key'=>null,'comment'=>'6-digit OTP code generated for the request.',),'purpose'=>array('type'=>'VARCHAR(20)','null'=>false,'default'=>'registration','extra'=>null,'key'=>'INDEX (composite: email_purpose)','comment'=>'Purpose of the OTP: registration, login, or password_reset.',),'created_at'=>array('type'=>'TIMESTAMP','null'=>false,'default'=>'CURRENT_TIMESTAMP','extra'=>null,'key'=>null,'comment'=>'Timestamp when the OTP was generated.',),'expires_at'=>array('type'=>'TIMESTAMP','null'=>false,'default'=>'CURRENT_TIMESTAMP','extra'=>null,'key'=>null,'comment'=>'Timestamp when the OTP expires (usually created_at + 10 min).',),'is_verified'=>array('type'=>'TINYINT(1)','null'=>false,'default'=>0,'extra'=>null,'key'=>null,'comment'=>'Whether the OTP has been verified: 0 = not verified, 1 = verified.',),'user_data'=>array('type'=>'TEXT','null'=>true,'default'=>null,'extra'=>null,'key'=>null,'comment'=>'JSON blob storing user registration data (username, email, password hash, etc.) until OTP is verified.',),);}public static function host_request_table_schema(){return array('id'=>array('type'=>'INT(11)','null'=>false,'default'=>null,'extra'=>'AUTO_INCREMENT','key'=>'PRIMARY','comment'=>'Unique auto-increment row identifier.',),'user_data'=>array('type'=>'LONGTEXT','null'=>true,'default'=>null,'extra'=>null,'key'=>null,'comment'=>'JSON blob containing the host application data: fullname, username, email, mobile, country code, etc.',),'status'=>array('type'=>'VARCHAR(50)','null'=>false,'default'=>'pending','extra'=>null,'key'=>null,'comment'=>'Application status: pending, approved, or rejected.',),'date'=>array('type'=>'DATETIME','null'=>true,'default'=>'CURRENT_TIMESTAMP','extra'=>null,'key'=>null,'comment'=>'Date & time when the host application was submitted.',),);}public static function otp_required_columns(){return array_keys(self::otp_table_schema());}public static function host_required_columns(){return array_keys(self::host_request_table_schema());}public static function otp_create_sql(){global $wpdb;$table=self::otp_table();$charset=$wpdb->get_charset_collate();return"CREATE TABLE {$table} (id INT(11) NOT NULL AUTO_INCREMENT,email VARCHAR(100) NOT NULL,otp_code VARCHAR(6) NOT NULL,purpose VARCHAR(20) NOT NULL DEFAULT 'registration',created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,expires_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,is_verified TINYINT(1) NOT NULL DEFAULT 0,user_data TEXT,PRIMARY KEY (id),KEY email_purpose (email,purpose)) {$charset};";}public static function host_request_create_sql(){global $wpdb;$table=self::host_request_table();$charset=$wpdb->get_charset_collate();return"CREATE TABLE {$table} (id INT(11) NOT NULL AUTO_INCREMENT,user_data LONGTEXT,status VARCHAR(50) NOT NULL DEFAULT 'pending',date DATETIME DEFAULT CURRENT_TIMESTAMP,PRIMARY KEY (id)) {$charset};";}}